theorem lem_HS_L1_to_moment_operator {E : Type*} [NormedAddCommGroup E] [InnerProductSpace ℂ E] [FiniteDimensional ℂ E]
    (mu η : MeasureTheory.Measure E) (k : ℕ) (hk : 1 ≤ k) :
    let Mmu : (E ⊗[ℂ] E) →l[ℂ] (E ⊗[ℂ] E) := ∫ u : E, (u ^⊗ k) ⊗ (u ^⊗ k) d_dtmu;
    let Mη : (E ⊗[ℂ] E) →l[ℂ] (E ⊗[ℂ] E) := ∫ u : E, (u ^⊗ k) ⊗ (u ^⊗ k) d_dtη;
    ‖Mmu - Mη‖_ℌ2 ≤ (∫ u : E, ‖u‖^(4 * k) d_dtmu + ∫ u : E, ‖u‖^(4 * k) d_dtη)^(1 / 2) * ‖mu - η‖_L1^(1 / 2)

